UPDATE words SET example_en_2 = 'She studied oenology at UC Davis.', example_ko_2 = '그녀는 UC Davis에서 포도주학을 공부했어요.', example_en_3 = 'Oenology explores the science behind every bottle.', example_ko_3 = '포도주학은 모든 와인 병 뒤에 숨겨진 과학을 탐구해요.', example_en_4 = 'A degree in oenology opens doors in the wine industry.', example_ko_4 = '포도주학 학위는 와인 업계의 문을 열어 줘요.', example_en_5 = 'Oenology and viticulture are often studied together.', example_ko_5 = '포도주학과 포도 재배학은 종종 함께 공부해요.' WHERE id = 'w_cafe_C2_01';
